import { useEffect, useRef, useState } from 'react';

import { useMouseHover } from '../../../../hooks/useMouseHover.js';
import { LegendItem } from '../types/legend.js';

export const useLegendItemState = (
  item: LegendItem,
  interactionsDisabled: boolean,
  hiddenItems: Set<string>,
  numberOfItems: number,
) => {
  const refIconButton = useRef<HTMLButtonElement>(null);
  const refNameButton = useRef<HTMLButtonElement>(null);

  const [open, setOpen] = useState(false);
  const [isHovered, setIsHovered] = useState(false);
  const isItemHidden = hiddenItems.has(item.id);

  // local visibility state for immediate rerendering
  const [visible, setVisible] = useState(!isItemHidden);

  const shouldShowActionsButton = open || isHovered;
  const isIconHovered =
    useMouseHover(refIconButton) && !interactionsDisabled && isHovered;
  const isLastSelectedItem =
    hiddenItems.size === numberOfItems - 1 && !isItemHidden;

  useEffect(() => setVisible(!isItemHidden), [isItemHidden]);

  return {
    refIconButton,
    refNameButton,
    open,
    shouldShowActionsButton,
    isIconHovered,
    visible,
    isLastItem: isLastSelectedItem,
    updateVisible: setVisible,
    updateOpenState: setOpen,
    updateHoveredState: setIsHovered,
  };
};
